import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import CourseSection from '../components/CourseSection';
import AboutSection from '../components/AboutSection';
import StatsSection from '../components/StatsSection';
import NewsSection from '../components/NewsSection';
import ContactSection from '../components/ContactSection';
import Hero from '../components/Hero';
import '../styles/HomePage.css';

const HomePage = () => {
    const [activeFilter, setActiveFilter] = useState('all');
    const [scrollY, setScrollY] = useState(0);

    // Parallax scrolling effect
    useEffect(() => {
        const handleScroll = () => setScrollY(window.scrollY);
        window.addEventListener('scroll', handleScroll);
        return () => window.removeEventListener('scroll', handleScroll);
    }, []);

    // Add animation effects when components enter viewport
    useEffect(() => {
        const observerOptions = {
            threshold: 0.1,
            rootMargin: '0px 0px -100px 0px'
        };

        const observer = new IntersectionObserver((entries) => {
            entries.forEach(entry => {
                if (entry.isIntersecting) {
                    entry.target.classList.add('visible');
                    // Add stagger effect for grid items
                    if (entry.target.classList.contains('bento-item')) {
                        const delay = entry.target.dataset.delay || 0;
                        setTimeout(() => {
                            entry.target.classList.add('animate-in');
                        }, delay * 100);
                    }
                }
            });
        }, observerOptions);

        const elements = document.querySelectorAll('.animate-on-scroll');
        elements.forEach(el => observer.observe(el));

        return () => observer.disconnect();
    }, []);

    const filters = [
        { id: 'all', icon: 'school', label: 'All Courses' },
        { id: 'web', icon: 'code', label: 'Web Development' },
        { id: 'data', icon: 'analytics', label: 'Data Science' },
        { id: 'security', icon: 'security', label: 'Cybersecurity' },
        { id: 'cloud', icon: 'cloud', label: 'Cloud Computing' },
        { id: 'ai', icon: 'smart_toy', label: 'Artificial Intelligence' }
    ];

    return (
        <div className="home-page">
            {/* Floating Orbs Background */}
            <div className="floating-orbs">
                <div className="orb orb1" style={{transform: `translateY(${scrollY * 0.1}px)`}}></div>
                <div className="orb orb2" style={{transform: `translateY(${scrollY * -0.1}px)`}}></div>
                <div className="orb orb3" style={{transform: `translateY(${scrollY * 0.05}px)`}}></div>
            </div>

            {/* Hero Section */}
            <Hero />

            {/* Course Catalog Section - Glassmorphism Design */}
            <section className="section courses-section" id="courses">
                <div className="container">
                    <div className="section-header animate-on-scroll">
                        <div className="section-badge">
                            <span className="badge-icon">✨</span>
                            Featured Programs
                        </div>
                        <h2>Explore Our Courses</h2>
                        <p>Cutting-edge programs designed to transform your career in tech</p>
                    </div>

                    {/* Course filters */}
                    <div className="filter-container animate-on-scroll">
                        {filters.map((filter) => (
                            <button
                                key={filter.id}
                                className={`filter-pill ${activeFilter === filter.id ? 'active' : ''}`}
                                onClick={() => setActiveFilter(filter.id)}
                            >
                                <span className="material-icons">{filter.icon}</span>
                                <span>{filter.label}</span>
                            </button>
                        ))}
                    </div>

                    <div className="course-wrapper animate-on-scroll">
                        <CourseSection />
                    </div>
                </div>
            </section>

            {/* About Section - Bento Grid Design */}
            <section className="section about-section" id="about">
                <div className="container">
                    <div className="section-header animate-on-scroll">
                        <div className="section-badge">
                            <span className="badge-icon">🚀</span>
                            Why Choose Us
                        </div>
                        <h2>Pioneering Tech Education</h2>
                        <p>Experience the future of technology education with industry-leading instructors and cutting-edge curriculum</p>
                    </div>

                    <div className="about-bento">
                        <div className="bento-item bento-main animate-on-scroll" data-delay="0">
                            <div className="bento-content">
                                <h3>Transforming Careers Since 2010</h3>
                                <p>We've been at the forefront of technology education for over a decade, constantly evolving our curriculum to match industry demands. Our graduates work at leading tech companies worldwide.</p>
                                <AboutSection />
                            </div>
                            <div className="bento-decoration"></div>
                        </div>

                        <div className="bento-item bento-stats animate-on-scroll" data-delay="1">
                            <div className="stat-grid">
                                <div className="stat-item">
                                    <div className="stat-number" data-value="15000">15K+</div>
                                    <div className="stat-label">Students Worldwide</div>
                                </div>
                                <div className="stat-item">
                                    <div className="stat-number" data-value="95">95%</div>
                                    <div className="stat-label">Job Placement Rate</div>
                                </div>
                                <div className="stat-item">
                                    <div className="stat-number" data-value="50">50+</div>
                                    <div className="stat-label">Expert Courses</div>
                                </div>
                                <div className="stat-item">
                                    <div className="stat-number" data-value="4.9">4.9★</div>
                                    <div className="stat-label">Student Rating</div>
                                </div>
                            </div>
                        </div>

                        <div className="bento-item bento-feature animate-on-scroll" data-delay="2">
                            <div className="bento-icon">
                                <span className="material-icons">school</span>
                            </div>
                            <h3>Expert Instructors</h3>
                            <p>Learn from industry professionals with real-world experience in top tech companies</p>
                            <div className="feature-link">
                                <Link to="/instructors">Meet our team →</Link>
                            </div>
                        </div>

                        <div className="bento-item bento-feature animate-on-scroll" data-delay="3">
                            <div className="bento-icon">
                                <span className="material-icons">trending_up</span>
                            </div>
                            <h3>Career Growth</h3>
                            <p>Accelerate your career with our comprehensive job placement assistance program</p>
                            <div className="feature-link">
                                <Link to="/careers">Learn more →</Link>
                            </div>
                        </div>

                        <div className="bento-item bento-feature animate-on-scroll" data-delay="4">
                            <div className="bento-icon">
                                <span className="material-icons">devices</span>
                            </div>
                            <h3>Flexible Learning</h3>
                            <p>Study at your own pace with our online and hybrid learning programs</p>
                            <div className="feature-link">
                                <Link to="/programs">View options →</Link>
                            </div>
                        </div>
                    </div>
                </div>
            </section>

            {/* Stats Section */}
            <section className="section stats-showcase" id="stats">
                <div className="container">
                    <div className="section-header animate-on-scroll">
                        <div className="section-badge">
                            <span className="badge-icon">📊</span>
                            Our Impact
                        </div>
                        <h2>Numbers That Matter</h2>
                        <p>The metrics that define our success in preparing the next generation of tech professionals</p>
                    </div>
                    <div className="stats-wrapper animate-on-scroll">
                        <StatsSection />
                    </div>
                </div>
            </section>

            {/* News Section - Modern Card Design */}
            <section className="section news-section" id="news">
                <div className="container">
                    <div className="section-header animate-on-scroll">
                        <div className="section-badge">
                            <span className="badge-icon">📰</span>
                            Latest Updates
                        </div>
                        <h2>News & Events</h2>
                        <p>Stay connected with the latest happenings in tech education</p>
                    </div>

                    <div className="news-grid">
                        <div className="news-card animate-on-scroll" data-delay="0">
                            <div className="news-image">
                                <div className="news-category">Announcement</div>
                            </div>
                            <div className="news-content">
                                <div className="news-meta">
                                    <span className="news-date">March 15, 2024</span>
                                    <span className="news-author">by Admin</span>
                                </div>
